class Solution:
    def rangeSumBST(self, root, low, high):
        total = 0
        stack = [root] if root else []
        while stack:
            node = stack.pop()
            if node is None:
                continue
            if low <= node.val <= high:
                total += node.val
            if node.left:
                stack.append(node.left)
            if node.right:
                stack.append(node.right)
        return total

